import { createStore } from 'vuex'

export default createStore({
  state: {
    // 用户信息
    user: null,
    // 当前处理中的小说
    currentNovel: null,
    // 处理中状态
    processingStatus: null,
    // 处理结果
    analysisResult: null,
    // 用户偏好设置
    preferences: {
      // 是否展示避雷标签
      showWarningTags: true,
      // 摘要详细程度 (简洁 0-1 详细)
      summaryDetailLevel: 0.5
    }
  },
  getters: {
    // 获取用户是否已登录
    isLoggedIn: (state) => {
      return state.user !== null
    },
    // 获取处理状态
    getProcessingStatus: (state) => {
      return state.processingStatus
    },
    // 获取分析结果
    getAnalysisResult: (state) => {
      return state.analysisResult
    },
    // 获取用户偏好
    getPreferences: (state) => {
      return state.preferences
    }
  },
  mutations: {
    // 设置用户信息
    SET_USER(state, user) {
      state.user = user
    },
    // 设置当前处理小说
    SET_CURRENT_NOVEL(state, novel) {
      state.currentNovel = novel
    },
    // 设置处理状态
    SET_PROCESSING_STATUS(state, status) {
      state.processingStatus = status
    },
    // 设置分析结果
    SET_ANALYSIS_RESULT(state, result) {
      state.analysisResult = result
    },
    // 更新用户偏好
    UPDATE_PREFERENCES(state, preferences) {
      state.preferences = { ...state.preferences, ...preferences }
    }
  },
  actions: {
    // 上传小说文件
    async uploadNovel({ commit }, { file, title, author }) {
      commit('SET_PROCESSING_STATUS', 'uploading')
      try {
        // 这里会调用后端 API
        // const response = await api.uploadNovel(file, title, author)
        const mockResponse = { 
          novelId: 1, 
          title, 
          status: 'processing' 
        }
        
        commit('SET_CURRENT_NOVEL', mockResponse)
        commit('SET_PROCESSING_STATUS', 'processing')
        return mockResponse
      } catch (error) {
        commit('SET_PROCESSING_STATUS', 'error')
        throw error
      }
    },
    
    // 获取小说分析结果
    async getNovelAnalysis({ commit }, novelId) {
      commit('SET_PROCESSING_STATUS', 'loading')
      try {
        // 这里会调用后端 API
        // const result = await api.getNovelAnalysis(novelId)
        const mockResult = {
          novelId,
          title: '测试小说',
          status: 'COMPLETED',
          summary: '这是一个测试小说的总体摘要，描述了主要情节和人物。',
          tags: {
            RECOMMEND: [
              { name: '强剧情驱动', description: '这本小说的强剧情驱动特点明显，值得推荐。' }
            ],
            WARNING: [
              { name: '注水章节多', description: '小说中存在大量与主线关系不大的填充内容。' }
            ]
          }
        }
        
        commit('SET_ANALYSIS_RESULT', mockResult)
        commit('SET_PROCESSING_STATUS', 'completed')
        return mockResult
      } catch (error) {
        commit('SET_PROCESSING_STATUS', 'error')
        throw error
      }
    },
    
    // 更新用户偏好设置
    updatePreferences({ commit }, preferences) {
      commit('UPDATE_PREFERENCES', preferences)
      // 实际项目中可能需要保存到本地存储
      localStorage.setItem('preferences', JSON.stringify(preferences))
    }
  },
  modules: {
    // 可以在这里添加模块化的store
  }
})
